const crypto = require('crypto');

function sha256Hex(s) {
  return crypto.createHash('sha256').update(String(s ?? ''), 'utf8').digest('hex');
}

function stripReplyPrefixes(subject) {
  // remove repeated RE:/FW:/FWD: etc at the start
  return String(subject ?? '')
    .replace(/^(\s*(re|fw|fwd)\s*:\s*)+/i, '')
    .trim();
}

function safeName(s, maxLen = 80) {
  // Windows/SharePoint friendly-ish filename component
  const cleaned = String(s ?? '')
    .replace(/[<>:"/\\|?*\x00-\x1F]/g, '') // illegal
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/\.$/, ''); // no trailing dot
  return cleaned.length > maxLen ? cleaned.slice(0, maxLen).trim() : cleaned;
}

function toUtcStamp(dt) {
  const d = new Date(dt);
  // guard: if invalid date, fall back to now
  const x = isNaN(d.getTime()) ? new Date() : d;
  const pad = (n) => String(n).padStart(2, '0');
  return `${x.getUTCFullYear()}${pad(x.getUTCMonth()+1)}${pad(x.getUTCDate())}-${pad(x.getUTCHours())}${pad(x.getUTCMinutes())}${pad(x.getUTCSeconds())}Z`;
}

return $input.all().map(item => {
  const j = item.json;

  const conversationId = j.conversationId ?? '';
  const internetMessageIdRaw = j.internetMessageId ?? '';
  const internetMessageIdClean = String(internetMessageIdRaw).trim().replace(/^<|>$/g, '');

  const convKey = sha256Hex(conversationId);
  const msgKey = sha256Hex(internetMessageIdClean);

  const conv8 = convKey.slice(0, 8);
  const msg8  = msgKey.slice(0, 8);

  const subjectClean = safeName(stripReplyPrefixes(j.subject ?? ''), 80);
  const threadFolderName = safeName(`${subjectClean} (c_${conv8})`, 120);

  const stamp = toUtcStamp(j.receivedDateTime ?? j.sentDateTime);
  const filePrefix = `${stamp}__m_${msg8}__`;

  return {
    json: {
      ...j,
      keyFields: {
        // stable keys
        conversationKey: convKey,
        messageKey: msgKey,
        // human + storage helpers
        subjectClean,
        threadFolderName,
        filePrefix,
        // keep originals for debugging/search
        internetMessageId: internetMessageIdRaw,
        internetMessageIdClean
      }
    }
  };
});

